draw(A--B--C--cycle);
dot(dots);
label("A(-3,1)",A,N);
label("B(7,1)",B,NE);
label("C(5,-3)",C,S);
label("D(5,1)",D,N);
xaxis(-5,9,Ticks(" ", xticks, 3),Arrows(4));
yaxis(-8,4,Ticks(" ", yticks, 3),Arrows(4));[/asy]

